def boundaryOfBinaryTree(root):
    if not root: return []
    def isLeaf(node): return not node.left and not node.right
    res = [root.val]
    # Left Boundary
    t = root.left
    while t:
        if not isLeaf(t): res.append(t.val)
        t = t.left if t.left else t.right
    # Leaves
    def addLeaves(node):
        if isLeaf(node): res.append(node.val); return
        if node.left: addLeaves(node.left)
        if node.right: addLeaves(node.right)
    if not isLeaf(root): addLeaves(root)
    # Right Boundary
    stack, t = [], root.right
    while t:
        if not isLeaf(t): stack.append(t.val)
        t = t.right if t.right else t.left
    res += stack[::-1]
    return res

